/// GET {merchantId}/accounttax
/// Lists the tax settings of the sub-accounts in your Merchant Center account.
///
/// Returns `ClientRequestBuilder` for customization.
/// Use `content_accounttax_list_execute()` to send, or `content_accounttax_list` for simplest API.

pub fn content_accounttax_list_builder(
    client: &SimpleHttpClient,
    merchantId: &str,
    maxResults: Option<i32>,
    pageToken: Option<&str>,
) -> Result<ClientRequestBuilder<SystemDnsResolver>, ApiError> {
    // Build URL
    let url = format!(
        "https://shoppingcontent.googleapis.com/content/v2.1/{}/accounttax",
        merchantId,
    );

    // Build request
    let mut query_parts = Vec::new();
    if let Some(val) = maxResults {
        query_parts.push(format!("maxResults={}", val));
    }
    if let Some(val) = pageToken {
        query_parts.push(format!("pageToken={}", val));
    }

    let url_with_query = if query_parts.is_empty() {
        url
    } else {
        format!("{}?{}", url, query_parts.join("&"))
    };

    let builder = client
        .get(&url_with_query)
        .map_err(|e| ApiError::RequestBuildFailed(e.to_string()))?;

    Ok(builder)
}

